hits <- grepGlob "^tidepool-[a-z-]+ = \\{ path" "tidepool-*/Cargo.toml"
let edges = map (\(f, _, t) -> (crateOf f, strip (head (splitOn " " t)))) hits
let cs = nub (map fst edges <> map snd edges)
let depsOf c = map snd (filter (\(a, _) -> a == c) edges)
let step m = fromList (map (\c -> (c, case depsOf c of { [] -> 0 :: Int; ds -> 1 + foldl' max' 0 (map (\d -> findWithDefault 0 d m) ds) })) cs)
let depths = converge step (fromList (map (\c -> (c, 0)) cs))
let tcStep m = fromList (map (\c -> (c, foldl' union (fromSetList (depsOf c)) (map (\d -> findWithDefault sempty d m) (depsOf c)))) cs)
let tc = converge tcStep (fromList (map (\c -> (c, sempty)) cs))
let rows = map (\(c, d) -> [c, pack (show d), pack (show (ssize (findWithDefault sempty c tc)))]) (sortBy (\a b -> compare (snd b) (snd a)) (toList depths))
putStrLn (renderTable (["crate", "build depth", "transitive deps"] : rows))
pure (object ["edges" .= length edges, "max_depth" .= foldl' max' 0 (map snd (toList depths))])

hits <- grepGlob "^tidepool-[a-z-]+ = \\{ path" "tidepool-*/Cargo.toml"
let edges = map (\(f, _, t) -> (crateOf f, strip (head (splitOn " " t)))) hits
let cs = nub (map fst edges <> map snd edges)
let depsOf c = map snd (filter (\(a, _) -> a == c) edges)
let step m = fromList (map (\c -> (c, case depsOf c of { [] -> 0 :: Int; ds -> 1 + foldl' max' 0 (map (\d -> findWithDefault 0 d m) ds) })) cs)
let depths = converge step (fromList (map (\c -> (c, 0)) cs))
let tcStep m = fromList (map (\c -> (c, sort (nub (depsOf c <> concatMap (\d -> findWithDefault [] d m) (depsOf c))))) cs)
let tc = converge tcStep (fromList (map (\c -> (c, [])) cs))
let rows = map (\(c, d) -> [c, pack (show d), pack (show (length (findWithDefault [] c tc)))]) (sortBy (\a b -> compare (snd b) (snd a)) (toList depths))
putStrLn (renderTable (["crate", "build depth", "transitive deps"] : rows))
pure (object ["edges" .= length edges, "max_depth" .= foldl' max' 0 (map snd (toList depths))])

(_, out, _) <- run "git log --oneline -30 --format='%s'"
let feats = length (filter (\l -> "feat" `isPrefixOf` l) (lines out))
let fixes = length (filter (\l -> "fix" `isPrefixOf` l) (lines out))
answer <- ask ("COROUTINE-B: last 30 commits = " <> pack (show feats) <> " feats, " <> pack (show fixes) <> " fixes. Compute ratio as percent? (yes/no)")
let yes = case answer of { String s -> "y" `isPrefixOf` toLower s; _ -> False }
pure (object ["coroutine" .= ("B" :: Text), "feats" .= feats, "fixes" .= fixes, "fix_pct" .= (if yes && (feats + fixes) > 0 then Just (div (100 * fixes) (feats + fixes)) else Nothing)])

